import React from 'react';
import './HomePage.scss';
import { useRouteMatch } from 'react-router';

export const HomePage = () => {
  const match = useRouteMatch();
  const { path } = match.params;

  return (

  <div className="HomePage" id={ path }>
    Home
  </div>
  );
};
